#include <stdio.h>
#include <math.h>
typedef struct{float x,y,z;}V;
static V v(float a,float b,float c){V r={a,b,c};return r;}
static V ad(V a,V b){return v(a.x+b.x,a.y+b.y,a.z+b.z);}
static V sb(V a,V b){return v(a.x-b.x,a.y-b.y,a.z-b.z);}
static V ml(V a,float s){return v(a.x*s,a.y*s,a.z*s);}
static float dt(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static V nm(V a){return ml(a,1.0f/sqrtf(dt(a,a)));}
static V C={0,-0.5f,-5};
static float hs(V o,V d){
  V oc=sb(o,C);
  float a=dt(d,d),b=2*dt(d,oc),c=dt(oc,oc)-1,D=b*b-4*a*c;
  if(D<0)return -1;
  float s=sqrtf(D),t=(-b-s)/(2*a);
  if(t<=0.001f)t=(-b+s)/(2*a);
  return t<=0.001f?-1:t;
}
int main(){
  int W=2400,H=1800,i,j;
  FILE*f=fopen("reconstructed.ppm","w");
  fprintf(f,"P3\n%d %d\n255\n",W,H);
  float vh=2.0f,vw=vh*W/H;
  V O=v(0,0,0),hor=v(vw,0,0),ver=v(0,vh,0),ll=v(-vw/2,-1,-1),L=nm(v(1,1,-1));
  for(j=0;j<H;j++)for(i=0;i<W;i++){
    float u=(float)i/(W-1),w=(float)j/(H-1);
    V d=nm(ad(ad(ll,ml(hor,u)),ml(ver,1.0f-w))),col,pt,n;
    float ts=hs(O,d),tp=1e30f;
    int ph=0,sp=0,hit=1;
    if(fabsf(d.y)>1e-4f){float t=(-1.5f-O.y)/d.y;if(t>0.001f){ph=1;tp=t;}}
    if(ts>0&&(!ph||ts<tp)){sp=1;pt=ad(O,ml(d,ts));n=nm(sb(pt,C));}
    else if(ph){pt=ad(O,ml(d,tp));n=v(0,1,0);}
    else hit=0;
    if(!hit){float t=0.5f*(d.y+1.0f);col=ad(ml(v(1,1,1),1.0f-t),ml(v(0.5f,0.7f,1.0f),t));}
    else{
      float df=dt(n,L);if(df<0)df=0;
      if(hs(ad(pt,ml(n,0.001f)),L)>0)df=0;
      float in=0.2f+0.8f*df;V base;
      if(sp)base=v(1,0.2f,0.2f);
      else{int e=((int)floorf(pt.x)+(int)floorf(pt.z))&1;base=e?v(0.4f,0.4f,0.4f):v(0.9f,0.9f,0.9f);}
      col=ml(base,in);
    }
    int r=(int)(255.99f*fminf(fmaxf(col.x,0),1));
    int g=(int)(255.99f*fminf(fmaxf(col.y,0),1));
    int b=(int)(255.99f*fminf(fmaxf(col.z,0),1));
    fprintf(f,"%d %d %d\n",r,g,b);
  }
  fclose(f);
  return 0;
}

